def main():
    n, q = map(int, input().split())
    lr = [list(map(int, input().split())) for _ in range(q)]
    lr.sort()
    ans = 0
    for i in range(q):
        for j in range(i+1, q):
            for k in range(j+1, q):
                x = set()
                for a, b in lr:
                    if a <= lr[i][0] and lr[i][0] <= b:
                        x.add(a)
                        x.add(b)
                    if a <= lr[j][0] and lr[j][0] <= b:
                        x.add(a)
                        x.add(b)
                    if a <= lr[k][0] and lr[k][0] <= b:
                        x.add(a)
                        x.add(b)
                ans = max(ans, len(x))
    print(ans)


if __name__ == '__main__':
    main()
